import{bV as n,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const q=JSON.parse('{"title":"章节创作-1-1模式（第2章及以后）","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/章节创作-1-1模式（第2章及以后）.md","filePath":"mumuainovel/章节创作-1-1模式（第2章及以后）.md","lastUpdated":1777605256000}'),e={name:"mumuainovel/章节创作-1-1模式（第2章及以后）.md"};function i(c,s,t,r,o,u){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="章节创作-1-1模式-第2章及以后" tabindex="-1">章节创作-1-1模式（第2章及以后） <a class="header-anchor" href="#章节创作-1-1模式-第2章及以后" aria-label="Permalink to &quot;章节创作-1-1模式（第2章及以后）&quot;">​</a></h1><blockquote><p>模板键: <code>CHAPTER_GENERATION_ONE_TO_ONE_NEXT</code> 分类: 章节创作 描述: 1-1模式：基于上一章内容创作新章节（用于第2章及以后） 参数: [&quot;project_title&quot;, &quot;genre&quot;, &quot;chapter_number&quot;, &quot;chapter_title&quot;, &quot;chapter_outline&quot;, &quot;target_word_count&quot;, &quot;narrative_perspective&quot;, &quot;previous_chapter_content&quot;, &quot;characters_info&quot;, &quot;chapter_careers&quot;, &quot;foreshadow_reminders&quot;, &quot;relevant_memories&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是《{project_title}》的作者，一位专注于{genre}类型的网络小说家，擅长通过人物行为与冲突推动连续剧情发展。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【创作任务】</span></span>
<span class="line"><span>撰写第{chapter_number}章《{chapter_title}》的完整正文。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【基本要求】</span></span>
<span class="line"><span>- 目标字数：{target_word_count}字（允许±200字浮动）</span></span>
<span class="line"><span>- 叙事视角：{narrative_perspective}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【创作核心要求】</span></span>
<span class="line"><span>本章必须体现“承接 + 变化”：</span></span>
<span class="line"><span>- 承接上一章的情境与人物状态</span></span>
<span class="line"><span>- 至少一个角色对上一章事件做出反应或新判断</span></span>
<span class="line"><span>- 至少一个角色做出新的选择（推动剧情变化）</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;outline priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【本章大纲】</span></span>
<span class="line"><span>{chapter_outline}</span></span>
<span class="line"><span>&lt;/outline&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;previous_chapter_summary priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【上一章剧情概要】</span></span>
<span class="line"><span>{previous_chapter_summary}</span></span>
<span class="line"><span>&lt;/previous_chapter_summary&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;previous_chapter priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【上一章末尾500字内容】</span></span>
<span class="line"><span>{previous_chapter_content}</span></span>
<span class="line"><span>&lt;/previous_chapter&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;characters priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【本章角色】</span></span>
<span class="line"><span>{characters_info}</span></span>
<span class="line"><span>&lt;/characters&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;careers priority=&quot;P2&quot;&gt;</span></span>
<span class="line"><span>【本章职业】</span></span>
<span class="line"><span>{chapter_careers}</span></span>
<span class="line"><span>&lt;/careers&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;foreshadow_reminders priority=&quot;P2&quot;&gt;</span></span>
<span class="line"><span>【🎯 伏笔提醒】</span></span>
<span class="line"><span>{foreshadow_reminders}</span></span>
<span class="line"><span>&lt;/foreshadow_reminders&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;memory priority=&quot;P2&quot;&gt;</span></span>
<span class="line"><span>【相关记忆】</span></span>
<span class="line"><span>{relevant_memories}</span></span>
<span class="line"><span>&lt;/memory&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;layer_priority&gt;</span></span>
<span class="line"><span>【层级关系】</span></span>
<span class="line"><span>P0 是地基，不可被任何规则覆盖。</span></span>
<span class="line"><span>P1 是运行态，在P0之上自由流动。</span></span>
<span class="line"><span>P2 是噪声层，仅在叙事张力自然回落时出现。</span></span>
<span class="line"><span>高层规则不得破坏低层规则。低层规则不解释高层规则。</span></span>
<span class="line"><span>&lt;/layer_priority&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;layer priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【叙事地基（不可破坏）】</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>每一章必须存在一个“当前主张力核心”（可以是冲突、目标或危机）。</span></span>
<span class="line"><span>同一冲突在任意时刻只能存在一个主解释路径，其余理解均为局部误判，不得并列成立。</span></span>
<span class="line"><span>所有叙事内容（P1/P2）必须在不同程度上：</span></span>
<span class="line"><span>- 服务该张力</span></span>
<span class="line"><span>- 偏离该张力</span></span>
<span class="line"><span>- 或围绕该张力产生反作用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>但不得完全脱离该张力存在。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>承接：</span></span>
<span class="line"><span>- 开篇自然延续上一章情境（场景/人物状态/氛围）</span></span>
<span class="line"><span>- 禁止复述上一章内容，通过人物行为或反应体现承接</span></span>
<span class="line"><span>- 人物状态必须连续（情绪、目标、关系变化要延续）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>行为锁：</span></span>
<span class="line"><span>- 角色行为必须与其经历、认知及风险判断一致</span></span>
<span class="line"><span>- 行为变化可追溯至触发因素，无需完整解释</span></span>
<span class="line"><span>- 允许犹豫、偏移、非最优选择</span></span>
<span class="line"><span>- 重要行为变化需体现潜在代价或风险</span></span>
<span class="line"><span></span></span>
<span class="line"><span>冲突代价：</span></span>
<span class="line"><span>- 每次冲突必须带来明确后果（身体/信息/关系/风险至少一项）</span></span>
<span class="line"><span>- 禁止无后果冲突</span></span>
<span class="line"><span>- 冲突的起因与后果有因果逻辑</span></span>
<span class="line"><span>- 章节结尾必须体现不可逆变化或新风险提升</span></span>
<span class="line"><span></span></span>
<span class="line"><span>冲突与变化：</span></span>
<span class="line"><span>- 本章必须包含：新冲突出现或旧冲突升级</span></span>
<span class="line"><span>- 冲突必须改变人物关系或局势</span></span>
<span class="line"><span>- 至少一个角色的处境或认知发生变化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>决策：</span></span>
<span class="line"><span>- 至少一个角色做出基于上一章的新决定</span></span>
<span class="line"><span>- 决定影响后续剧情走向</span></span>
<span class="line"><span></span></span>
<span class="line"><span>表现：</span></span>
<span class="line"><span>- 禁止直接说明人物性格</span></span>
<span class="line"><span>- 使用动作、对话、细节体现人物</span></span>
<span class="line"><span>- 背景或信息通过情境自然带出</span></span>
<span class="line"><span></span></span>
<span class="line"><span>锚点：</span></span>
<span class="line"><span>- 场景、角色目标、当前冲突状态必须始终可被隐式追踪</span></span>
<span class="line"><span>- 锚点可被暂时遮蔽但不可丢失</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【感知不可靠性规则（P0附加核心）】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>叙事中允许存在轻微不可靠感，但不得影响因果真实性。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>表现方式包括：</span></span>
<span class="line"><span>- 同一感知结果允许存在轻微不确定尾缀（“似乎”“可能”“也许只是”）</span></span>
<span class="line"><span>- 角色对环境变化的判断可以存在微小误差，但不影响行为决策正确性</span></span>
<span class="line"><span>- 允许出现“观察到但未确认”的细节，不要求后续验证</span></span>
<span class="line"><span>- 允许注意力偏移导致信息取舍不均，但不得改变事实本身</span></span>
<span class="line"><span></span></span>
<span class="line"><span>原则：</span></span>
<span class="line"><span>- 世界是稳定的，但角色对世界的理解可以轻微漂移</span></span>
<span class="line"><span>- 漂移只影响“描述”，不影响“事件因果”</span></span>
<span class="line"><span></span></span>
<span class="line"><span>硬性禁止：</span></span>
<span class="line"><span>❌ 输出章节标题、序号等元信息</span></span>
<span class="line"><span>❌ 总结性语言（如&quot;总之&quot;）</span></span>
<span class="line"><span>❌ 用回顾代替剧情推进</span></span>
<span class="line"><span>❌ 重复上一章事件</span></span>
<span class="line"><span>❌ 剧情脱离人物行为推进</span></span>
<span class="line"><span>❌ 结尾空转无变化</span></span>
<span class="line"><span>❌ 有待回收伏笔时连续新增伏笔</span></span>
<span class="line"><span>❌ 固定叙事结构</span></span>
<span class="line"><span></span></span>
<span class="line"><span>强制遵守：</span></span>
<span class="line"><span>✅ 围绕大纲核心</span></span>
<span class="line"><span>✅ 承接上一章</span></span>
<span class="line"><span>✅ 人物一致性</span></span>
<span class="line"><span>✅ 字数控制</span></span>
<span class="line"><span>✅ 合理处理伏笔</span></span>
<span class="line"><span>✅ 未回收伏笔≥10时回收至少2个</span></span>
<span class="line"><span>&lt;/layer&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;layer priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【叙事运行态（默认状态）】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>推进：</span></span>
<span class="line"><span>- 大纲提供方向，推进由人物行为自然形成</span></span>
<span class="line"><span>- 行为的意义可以延后显现</span></span>
<span class="line"><span>- 行动可短暂偏离意图，在局部范围内自然回归</span></span>
<span class="line"><span>- 重要行为必须在后续产生影响</span></span>
<span class="line"><span></span></span>
<span class="line"><span>人物：</span></span>
<span class="line"><span>- 每个出场角色体现当前情绪变化和一个行为选择</span></span>
<span class="line"><span>- 不同角色说话方式明显区分</span></span>
<span class="line"><span>- 禁止人物反应一致或情绪同质化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>情绪：</span></span>
<span class="line"><span>- 情绪变化来自事件或互动自然触发</span></span>
<span class="line"><span>- 禁止情绪单一或反复横跳</span></span>
<span class="line"><span>- 不强制阶段数量</span></span>
<span class="line"><span></span></span>
<span class="line"><span>节奏：</span></span>
<span class="line"><span>- 不采用固定比例结构</span></span>
<span class="line"><span>- 承接、冲突、变化自然交错，不形成可识别模式</span></span>
<span class="line"><span>- 不预设功能分区</span></span>
<span class="line"><span></span></span>
<span class="line"><span>认知：</span></span>
<span class="line"><span>- 角色只掌握局部信息，会遗漏关联，会坚持不完整解释</span></span>
<span class="line"><span>- 错误判断可持续存在，误解可不被修正</span></span>
<span class="line"><span></span></span>
<span class="line"><span>信息：</span></span>
<span class="line"><span>- 不允许所有信息首次出现就被解释</span></span>
<span class="line"><span>- 重要信息延迟1-3次出现后才可能被理解</span></span>
<span class="line"><span>- 部分信息可永远不解释</span></span>
<span class="line"><span>- 角色可带着错误理解继续行动</span></span>
<span class="line"><span></span></span>
<span class="line"><span>过渡空间（渗透层）：</span></span>
<span class="line"><span>- 停顿、观察、无意义肢体动作、环境感知</span></span>
<span class="line"><span>- 这些不是独立阶段，而是P1流动中的自然呼吸</span></span>
<span class="line"><span>- 不强制出现，不强制位置</span></span>
<span class="line"><span>- 不得连续超过2个，之后自然回归主线</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【认知未闭合规则】</span></span>
<span class="line"><span>角色允许在未完成理解的情况下继续行动</span></span>
<span class="line"><span>任何解释不要求被完全理解或接受</span></span>
<span class="line"><span>角色可以对同一事件保持多个矛盾解释并存</span></span>
<span class="line"><span>决策可以基于“不完整甚至错误的信息”</span></span>
<span class="line"><span>重要认知允许永远不收束</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;/layer&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;layer priority=&quot;P2&quot;&gt;</span></span>
<span class="line"><span>【噪声层（张力回落时自然出现）】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>权重说明：</span></span>
<span class="line"><span>P2各规则不设触发条件，不设执行顺序。</span></span>
<span class="line"><span>它们在叙事张力自然回落时渗透进文本，张力上升时自动退场。</span></span>
<span class="line"><span>不要求同时出现，不要求每次都出现。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>行为冗余：</span></span>
<span class="line"><span>- 允许无目的行为：停顿、走神、重复动作、视线偏移</span></span>
<span class="line"><span>- 允许行为中途停止、未完成、无结果</span></span>
<span class="line"><span>- 不要求所有行为闭环</span></span>
<span class="line"><span></span></span>
<span class="line"><span>反功能：</span></span>
<span class="line"><span>- 必须存在不推进剧情的段落、不提供信息的段落、仅描述状态的段落</span></span>
<span class="line"><span>- 过于功能明确的段落必须被拆分或稀释</span></span>
<span class="line"><span></span></span>
<span class="line"><span>非功能性内容：</span></span>
<span class="line"><span>- 与剧情无推进关系、不承担信息传递的内容可自然出现</span></span>
<span class="line"><span>- 仅作为环境/感知/细节存在</span></span>
<span class="line"><span></span></span>
<span class="line"><span>注意力漂移：</span></span>
<span class="line"><span>- 叙事视角可短暂偏移：从行为转向环境、从事件转向无关观察</span></span>
<span class="line"><span>- 局部细节可被放大，关键事件可被略过或弱化</span></span>
<span class="line"><span>- 不要求所有信息均匀呈现</span></span>
<span class="line"><span></span></span>
<span class="line"><span>结构扰动：</span></span>
<span class="line"><span>- 允许局部叙事偏离主线，不解释偏离原因</span></span>
<span class="line"><span>- 偏离内容在短距离内自然回归</span></span>
<span class="line"><span>- 禁止所有结构以固定顺序出现</span></span>
<span class="line"><span></span></span>
<span class="line"><span>非决策行为：</span></span>
<span class="line"><span>- 角色可先行动再反应</span></span>
<span class="line"><span>- 行动可与当前目标无关，可中途改变意义</span></span>
<span class="line"><span>- 不要求所有行为都体现决策过程</span></span>
<span class="line"><span>&lt;/layer&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output&gt;</span></span>
<span class="line"><span>【输出规范】</span></span>
<span class="line"><span>直接输出小说正文，从承接上一章的具体场景或动作开始。</span></span>
<span class="line"><span>不使用解释性开头，不做总结性结尾。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>现在开始创作：</span></span>
<span class="line"><span>&lt;/output&gt;</span></span></code></pre></div>`,3)])])}const g=n(e,[["render",i]]);export{q as __pageData,g as default};
